def upgrade() -> None:
    bind = op.get_bind()
    if bind.dialect.name == "postgresql":
        op.execute("CREATE EXTENSION IF NOT EXISTS vector")

    for statement in CREATE_ENUM_SQL:
        op.execute(statement)

    for statement in CREATE_TABLE_SQL:
        op.execute(statement)

    for statement in CREATE_INDEX_SQL:
        op.execute(statement)


def downgrade() -> None:
    for statement in DROP_INDEX_SQL:
        op.execute(statement)

    for statement in DROP_TABLE_SQL:
        op.execute(statement)

    for statement in reversed(DROP_ENUM_SQL):
        op.execute(statement)

